// Aggregate employee data into manager dashboard shape
const employees = $input.all().map(i => i.json);

// --- Department rollup ---
const deptMap = {};
for (const emp of employees) {
  const dept = emp.department || 'Other';
  if (!deptMap[dept]) {
    deptMap[dept] = { name: dept, learners: 0, managers: new Set(), employees: [] };
  }
  deptMap[dept].learners++;
  deptMap[dept].employees.push({
    name: emp.full_name,
    email: emp.email,
    title: emp.title,
    subTeam: emp.sub_team,
    hireDate: emp.hire_date,
  });
  if (emp.manager_name) {
    deptMap[dept].managers.add(emp.manager_name);
  }
}

const departments = Object.values(deptMap)
  .map(d => ({
    name: d.name,
    learners: d.learners,
    managers: [...d.managers],
    employees: d.employees,
  }))
  .sort((a, b) => b.learners - a.learners);

// --- Manager rollup ---
const mgrMap = {};
for (const emp of employees) {
  const mgr = emp.manager_name || 'No Manager';
  const mgrEmail = emp.manager_email || '';
  if (!mgrMap[mgr]) {
    mgrMap[mgr] = {
      name: mgr,
      email: mgrEmail,
      department: emp.department,
      directReports: 0,
      reportNames: [],
    };
  }
  mgrMap[mgr].directReports++;
  mgrMap[mgr].reportNames.push(emp.full_name);
}

const managers = Object.values(mgrMap)
  .filter(m => m.name !== 'No Manager')
  .sort((a, b) => b.directReports - a.directReports);

// --- Overview ---
const overview = {
  totalEmployees: employees.length,
  totalDepartments: departments.length,
  totalManagers: managers.length,
};

return [{
  json: {
    overview,
    departments,
    managers,
    employeeCount: employees.length,
    generatedAt: new Date().toISOString(),
  }
}];
